namespace ContosoUniversity.Tests.Controllers
{
    public class NotificationsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly NotificationsController _controller;
        private readonly NotificationService _notificationService;

        public NotificationsControllerTests()
        {
            _context = TestHelpers.CreateInMemoryContext();
            _controller = new NotificationsController(_context);
            _notificationService = new NotificationService();
            // Drain any leftover notifications
            while (_notificationService.ReceiveNotification() != null) { }
        }

        public void Dispose()
        {
            while (_notificationService.ReceiveNotification() != null) { }
            _controller.Dispose();
            _context.Dispose();
            _notificationService.Dispose();
        }

        [Fact]
        public void GetNotifications_EmptyQueue_ReturnsSuccessWithEmptyList()
        {
            var result = _controller.GetNotifications();

            var jsonResult = Assert.IsType<JsonResult>(result);
            Assert.NotNull(jsonResult.Value);
        }

        [Fact]
        public void GetNotifications_WithNotifications_ReturnsNotifications()
        {
            // Enqueue notifications via the shared static queue
            _notificationService.SendNotification("Student", "1", "Test", EntityOperation.CREATE);

            var result = _controller.GetNotifications();

            var jsonResult = Assert.IsType<JsonResult>(result);
            Assert.NotNull(jsonResult.Value);
        }

        [Fact]
        public void MarkAsRead_ReturnsJsonSuccess()
        {
