namespace ContosoUniversity.Tests.Data
{
    public class SchoolContextTests : IDisposable
    {
        private readonly SchoolContext _context;

        public SchoolContextTests()
        {
            _context = TestHelpers.CreateInMemoryContext();
        }

        public void Dispose()
        {
            _context.Dispose();
        }

        [Fact]
        public void CanAddAndRetrieveStudent()
        {
            var student = new Student
            {
                FirstMidName = "Test",
                LastName = "Student",
                EnrollmentDate = DateTime.Today
            };

            _context.Students.Add(student);
            _context.SaveChanges();

            var retrieved = _context.Students.First();
            Assert.Equal("Student", retrieved.LastName);
        }

        [Fact]
        public void CanAddAndRetrieveInstructor()
        {
            var instructor = new Instructor
            {
                FirstMidName = "Test",
                LastName = "Instructor",
                HireDate = DateTime.Today
            };

            _context.Instructors.Add(instructor);
            _context.SaveChanges();

            var retrieved = _context.Instructors.First();
            Assert.Equal("Instructor", retrieved.LastName);
        }

        [Fact]
        public void CanAddCourseWithDepartment()
        {
            var dept = new Department
            {
                Name = "Test Dept",
                Budget = 50000,
                StartDate = DateTime.Today
            };
            _context.Departments.Add(dept);
            _context.SaveChanges();

            var course = new Course
            {
                CourseID = 5000,
                Title = "Test Course",
                Credits = 3,
                DepartmentID = dept.DepartmentID
            };
            _context.Courses.Add(course);
            _context.SaveChanges();

            var retrieved = _context.Courses.Find(5000);
            Assert.NotNull(retrieved);
            Assert.Equal("Test Course", retrieved.Title);
        }

        [Fact]
        public void CanCreateEnrollmentRelationship()
        {
            var student = new Student { FirstMidName = "A", LastName = "B", EnrollmentDate = DateTime.Today };
            _context.Students.Add(student);

            var dept = new Department { Name = "D", Budget = 1000, StartDate = DateTime.Today };
            _context.Departments.Add(dept);
            _context.SaveChanges();

            var course = new Course { CourseID = 6000, Title = "C", Credits = 1, DepartmentID = dept.DepartmentID };
            _context.Courses.Add(course);
            _context.SaveChanges();

            var enrollment = new Enrollment { StudentID = student.ID, CourseID = 6000, Grade = Grade.A };
            _context.Enrollments.Add(enrollment);
            _context.SaveChanges();

            Assert.Single(_context.Enrollments);
        }

        [Fact]
        public void CourseAssignment_CompositeKey_Works()
        {
            var instructor = new Instructor { FirstMidName = "A", LastName = "B", HireDate = DateTime.Today };
            _context.Instructors.Add(instructor);

            var dept = new Department { Name = "D", Budget = 1000, StartDate = DateTime.Today };
            _context.Departments.Add(dept);
            _context.SaveChanges();

            var course = new Course { CourseID = 7000, Title = "C", Credits = 1, DepartmentID = dept.DepartmentID };
            _context.Courses.Add(course);
            _context.SaveChanges();

            var assignment = new CourseAssignment { CourseID = 7000, InstructorID = instructor.ID };
            _context.CourseAssignments.Add(assignment);
            _context.SaveChanges();

            var found = _context.CourseAssignments.Find(7000, instructor.ID);
            Assert.NotNull(found);
        }

        [Fact]
        public void CanAddOfficeAssignment()
        {
            var instructor = new Instructor { FirstMidName = "A", LastName = "B", HireDate = DateTime.Today };
            _context.Instructors.Add(instructor);
            _context.SaveChanges();

            var oa = new OfficeAssignment { InstructorID = instructor.ID, Location = "Room 101" };
            _context.OfficeAssignments.Add(oa);
            _context.SaveChanges();

            var found = _context.OfficeAssignments.Find(instructor.ID);
            Assert.NotNull(found);
            Assert.Equal("Room 101", found.Location);
        }

        [Fact]
        public void CanAddNotification()
        {
            var notification = new Notification
            {
                EntityType = "Student",
                EntityId = "1",
                Operation = "CREATE",
                Message = "Test",
                CreatedAt = DateTime.Now,
                CreatedBy = "System",
                IsRead = false
            };
            _context.Notifications.Add(notification);
            _context.SaveChanges();

            Assert.Single(_context.Notifications);
        }

        [Fact]
        public void DbSets_AreInitialized()
        {
            Assert.NotNull(_context.Courses);
            Assert.NotNull(_context.Enrollments);
            Assert.NotNull(_context.Departments);
            Assert.NotNull(_context.OfficeAssignments);
            Assert.NotNull(_context.CourseAssignments);
            Assert.NotNull(_context.People);
            Assert.NotNull(_context.Students);
            Assert.NotNull(_context.Instructors);
            Assert.NotNull(_context.Notifications);
        }
    }

    public class DbInitializerTests
    {
        [Fact]
        public void Initialize_SeedsData()
        {
            var context = TestHelpers.CreateInMemoryContext();

            DbInitializer.Initialize(context);

            Assert.Equal(8, context.Students.Count());
            Assert.Equal(5, context.Instructors.Count());
            Assert.Equal(4, context.Departments.Count());
            Assert.Equal(7, context.Courses.Count());
            Assert.True(context.Enrollments.Count() > 0);
            Assert.True(context.OfficeAssignments.Count() > 0);
            Assert.True(context.CourseAssignments.Count() > 0);

            context.Dispose();
        }

        [Fact]
        public void Initialize_DoesNotReseed_WhenStudentsExist()
        {
            var context = TestHelpers.CreateInMemoryContext();

            // First seed
            DbInitializer.Initialize(context);
            var initialCount = context.Students.Count();

            // Second seed should be no-op
            DbInitializer.Initialize(context);
            Assert.Equal(initialCount, context.Students.Count());

            context.Dispose();
        }
    }
}

