            Assert.Null(_context.Courses.Find(1050));
        }

        [Fact]
        public void DeleteConfirmed_CourseWithImage_DeletesImageFile()
        {
            // Set up a course with an image
            var uploadsPath = Path.Combine(_tempDir, "Uploads", "TeachingMaterials");
            Directory.CreateDirectory(uploadsPath);
            var imageFile = Path.Combine(uploadsPath, "test_image.jpg");
            File.WriteAllText(imageFile, "test");

            var course = _context.Courses.Find(1050);
            course.TeachingMaterialImagePath = "/Uploads/TeachingMaterials/test_image.jpg";
            _context.SaveChanges();

            _controller.DeleteConfirmed(1050);

            Assert.False(File.Exists(imageFile));
        }

        #endregion

        #region Helpers

        private static Mock<IFormFile> CreateMockFormFile(string fileName, string contentType, long length)
        {
            var mockFile = new Mock<IFormFile>();
            mockFile.Setup(f => f.FileName).Returns(fileName);
            mockFile.Setup(f => f.ContentType).Returns(contentType);
            mockFile.Setup(f => f.Length).Returns(length);

            var content = new byte[Math.Min(length, 1024)]; // don't allocate huge arrays for test
            var stream = new MemoryStream(content);
            mockFile.Setup(f => f.CopyTo(It.IsAny<Stream>()))
                .Callback<Stream>(s => stream.CopyTo(s));

            return mockFile;
        }

        #endregion
    }
