            _context.Courses.Add(course);
            _context.SaveChanges();

            var enrollment = new Enrollment { StudentID = student.ID, CourseID = 6000, Grade = Grade.A };
            _context.Enrollments.Add(enrollment);
            _context.SaveChanges();

            Assert.Single(_context.Enrollments);
        }

