                Message = "Test",
                CreatedAt = DateTime.Now,
                CreatedBy = "System",
                IsRead = false
            };
            _context.Notifications.Add(notification);
            _context.SaveChanges();

            Assert.Single(_context.Notifications);
        }

        [Fact]
        public void DbSets_AreInitialized()
        {
