using System;
using Xunit;
using ContosoUniversity.Models;

namespace ContosoUniversity.Tests.Models
{
    public class PersonTests
    {
        private class ConcretePerson : Person { }

        [Fact]
        public void FullName_ReturnsLastNameCommaFirstName()
        {
            var person = new ConcretePerson { FirstMidName = "Carson", LastName = "Alexander" };
            Assert.Equal("Alexander, Carson", person.FullName);
        }

        [Fact]
        public void FullName_WithNullNames_StillConcatenates()
        {
            var person = new ConcretePerson { FirstMidName = null, LastName = null };
            Assert.Equal(", ", person.FullName);
        }
    }

    public class StudentTests
    {
        [Fact]
        public void Student_InheritsFromPerson()
        {
            var student = new Student { FirstMidName = "Test", LastName = "Student", EnrollmentDate = DateTime.Today };
            Assert.IsAssignableFrom<Person>(student);
        }

        [Fact]
        public void Student_FullName_Works()
        {
            var student = new Student { FirstMidName = "Jane", LastName = "Doe" };
            Assert.Equal("Doe, Jane", student.FullName);
        }

        [Fact]
        public void Student_EnrollmentDate_CanBeSet()
        {
            var date = new DateTime(2020, 9, 1);
            var student = new Student { EnrollmentDate = date };
            Assert.Equal(date, student.EnrollmentDate);
        }
    }

    public class InstructorTests
    {
        [Fact]
        public void Instructor_InheritsFromPerson()
        {
            var instructor = new Instructor { FirstMidName = "Test", LastName = "Inst", HireDate = DateTime.Today };
            Assert.IsAssignableFrom<Person>(instructor);
        }

        [Fact]
        public void Instructor_FullName_Works()
        {
            var instructor = new Instructor { FirstMidName = "Kim", LastName = "Abercrombie" };
            Assert.Equal("Abercrombie, Kim", instructor.FullName);
        }

        [Fact]
        public void Instructor_HireDate_CanBeSet()
        {
            var date = new DateTime(1995, 3, 11);
            var instructor = new Instructor { HireDate = date };
            Assert.Equal(date, instructor.HireDate);
        }
    }

    public class ErrorViewModelTests
    {
        [Fact]
        public void ShowRequestId_ReturnsFalse_WhenNull()
        {
            var model = new ErrorViewModel { RequestId = null };
            Assert.False(model.ShowRequestId);
        }

        [Fact]
        public void ShowRequestId_ReturnsFalse_WhenEmpty()
        {
            var model = new ErrorViewModel { RequestId = "" };
            Assert.False(model.ShowRequestId);
        }

        [Fact]
        public void ShowRequestId_ReturnsTrue_WhenHasValue()
        {
            var model = new ErrorViewModel { RequestId = "abc-123" };
            Assert.True(model.ShowRequestId);
        }
    }

    public class CourseTests
    {
        [Fact]
        public void Course_Properties_CanBeSet()
        {
            var course = new Course
            {
                CourseID = 1050,
                Title = "Chemistry",
                Credits = 3,
                DepartmentID = 1,
                TeachingMaterialImagePath = "/uploads/test.jpg"
            };

            Assert.Equal(1050, course.CourseID);
            Assert.Equal("Chemistry", course.Title);
            Assert.Equal(3, course.Credits);
            Assert.Equal(1, course.DepartmentID);
            Assert.Equal("/uploads/test.jpg", course.TeachingMaterialImagePath);
        }
    }

    public class EnrollmentTests
    {
        [Fact]
        public void Enrollment_Grade_CanBeNull()
        {
            var enrollment = new Enrollment { EnrollmentID = 1, CourseID = 1, StudentID = 1 };
            Assert.Null(enrollment.Grade);
        }

        [Fact]
        public void Enrollment_Grade_CanBeSet()
        {
            var enrollment = new Enrollment { Grade = Grade.A };
            Assert.Equal(Grade.A, enrollment.Grade);
        }

        [Theory]
        [InlineData(Grade.A)]
        [InlineData(Grade.B)]
        [InlineData(Grade.C)]
        [InlineData(Grade.D)]
        [InlineData(Grade.F)]
        public void Grade_HasExpectedValues(Grade grade)
        {
            var enrollment = new Enrollment { Grade = grade };
            Assert.Equal(grade, enrollment.Grade);
        }
    }

    public class DepartmentTests
    {
        [Fact]
        public void Department_Properties_CanBeSet()
        {
            var dept = new Department
            {
                DepartmentID = 1,
                Name = "Engineering",
                Budget = 350000m,
                StartDate = new DateTime(2007, 9, 1),
                InstructorID = 5
            };

            Assert.Equal(1, dept.DepartmentID);
            Assert.Equal("Engineering", dept.Name);
            Assert.Equal(350000m, dept.Budget);
            Assert.Equal(5, dept.InstructorID);
        }

        [Fact]
        public void Department_InstructorID_CanBeNull()
        {
            var dept = new Department { Name = "Test" };
            Assert.Null(dept.InstructorID);
        }
    }

    public class NotificationTests
    {
        [Fact]
        public void Notification_Properties_CanBeSet()
        {
            var now = DateTime.Now;
            var notification = new Notification
            {
                Id = 1,
                EntityType = "Student",
                EntityId = "42",
                Operation = "CREATE",
                Message = "New Student has been created",
                CreatedAt = now,
                CreatedBy = "System",
                IsRead = false,
                ReadAt = null
            };

            Assert.Equal(1, notification.Id);
            Assert.Equal("Student", notification.EntityType);
            Assert.Equal("42", notification.EntityId);
            Assert.Equal("CREATE", notification.Operation);
            Assert.False(notification.IsRead);
            Assert.Null(notification.ReadAt);
        }

        [Fact]
        public void Notification_CanBeMarkedAsRead()
        {
            var readTime = DateTime.Now;
            var notification = new Notification { IsRead = true, ReadAt = readTime };

            Assert.True(notification.IsRead);
            Assert.Equal(readTime, notification.ReadAt);
        }
    }

    public class EntityOperationTests
    {
        [Fact]
        public void EntityOperation_HasExpectedValues()
        {
            Assert.Equal(0, (int)EntityOperation.CREATE);
            Assert.Equal(1, (int)EntityOperation.UPDATE);
            Assert.Equal(2, (int)EntityOperation.DELETE);
        }
    }

    public class CourseAssignmentTests
    {
        [Fact]
        public void CourseAssignment_Properties_CanBeSet()
        {
            var ca = new CourseAssignment { InstructorID = 1, CourseID = 1050 };
            Assert.Equal(1, ca.InstructorID);
            Assert.Equal(1050, ca.CourseID);
        }
    }

    public class OfficeAssignmentTests
    {
        [Fact]
        public void OfficeAssignment_Properties_CanBeSet()
        {
            var oa = new OfficeAssignment { InstructorID = 1, Location = "Smith 17" };
            Assert.Equal(1, oa.InstructorID);
            Assert.Equal("Smith 17", oa.Location);
        }
    }
}

