using System;
using System.Collections.Generic;
using System.Linq;
using System.Net;
using Xunit;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Models.SchoolViewModels;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;

namespace ContosoUniversity.Tests.Controllers
{
    public class InstructorsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly InstructorsController _controller;

        public InstructorsControllerTests()
        {
            _context = TestHelpers.CreateInMemoryContext();
            TestHelpers.SeedDatabase(_context);
            _controller = new InstructorsController(_context);
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        #region Index

        [Fact]
        public void Index_NoParams_ReturnsViewWithInstructorData()
        {
            var result = _controller.Index(null, null);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<InstructorIndexData>(viewResult.Model);
            Assert.NotNull(model.Instructors);
            Assert.Equal(2, model.Instructors.Count());
        }

        [Fact]
        public void Index_WithInstructorId_ShowsCourses()
        {
            var result = _controller.Index(10, null);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<InstructorIndexData>(viewResult.Model);
            Assert.NotNull(model.Courses);
            Assert.Single(model.Courses); // Instructor 10 teaches course 1050
        }

        [Fact]
        public void Index_WithInstructorAndCourseId_ShowsEnrollments()
        {
            var result = _controller.Index(10, 1050);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<InstructorIndexData>(viewResult.Model);
            Assert.NotNull(model.Enrollments);
        }

        [Fact]
        public void Index_SetsViewBagInstructorID()
        {
            _controller.Index(10, null);

            Assert.Equal(10, _controller.ViewBag.InstructorID);
        }

        [Fact]
        public void Index_SetsViewBagCourseID()
        {
            _controller.Index(10, 1050);

            Assert.Equal(1050, _controller.ViewBag.CourseID);
        }

        [Fact]
        public void Index_InstructorsOrderedByLastName()
        {
            var result = _controller.Index(null, null);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<InstructorIndexData>(viewResult.Model);
            var instructors = model.Instructors.ToList();
            Assert.Equal("Abercrombie", instructors[0].LastName);
            Assert.Equal("Fakhouri", instructors[1].LastName);
        }

        #endregion

        #region Details

        [Fact]
        public void Details_NullId_ReturnsBadRequest()
        {
            var result = _controller.Details(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal((int)HttpStatusCode.BadRequest, statusResult.StatusCode);
        }

        [Fact]
        public void Details_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Details(999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Details_ValidId_ReturnsViewWithInstructor()
        {
            var result = _controller.Details(10);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<Instructor>(viewResult.Model);
            Assert.Equal("Abercrombie", model.LastName);
        }

        #endregion

        #region Create GET

        [Fact]
        public void Create_GET_ReturnsViewWithInstructor()
        {
            var result = _controller.Create();

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<Instructor>(viewResult.Model);
            Assert.NotNull(model.CourseAssignments);
            Assert.Empty(model.CourseAssignments);
            Assert.NotNull(_controller.ViewBag.Courses);
        }

        [Fact]
        public void Create_GET_PopulatesAssignedCourses()
        {
            _controller.Create();

            var courses = _controller.ViewBag.Courses as List<AssignedCourseData>;
            Assert.NotNull(courses);
            Assert.Equal(3, courses.Count); // 3 courses in seed data
            Assert.All(courses, c => Assert.False(c.Assigned)); // none assigned to new instructor
        }

        #endregion

        #region Create POST

        [Fact]
        public void Create_POST_ValidInstructor_NoCourses_RedirectsToIndex()
        {
            var instructor = new Instructor
            {
                FirstMidName = "New",
                LastName = "Instructor",
                HireDate = new DateTime(2020, 1, 1)
            };

            var result = _controller.Create(instructor, null);

            var redirectResult = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirectResult.ActionName);
            Assert.Equal(3, _context.Instructors.Count());
        }

        [Fact]
        public void Create_POST_ValidInstructor_WithCourses_AddsCourseAssignments()
        {
            var instructor = new Instructor
            {
                FirstMidName = "New",
                LastName = "Instructor",
                HireDate = new DateTime(2020, 1, 1)
            };

            var selectedCourses = new[] { "1050", "4022" };

            var result = _controller.Create(instructor, selectedCourses);

            var redirectResult = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirectResult.ActionName);

            var saved = _context.Instructors.First(i => i.LastName == "Instructor");
            var assignments = _context.CourseAssignments.Where(ca => ca.InstructorID == saved.ID).ToList();
            Assert.Equal(2, assignments.Count);
        }

        [Fact]
        public void Create_POST_InvalidModelState_ReturnsView()
        {
            _controller.ModelState.AddModelError("LastName", "Required");
            var instructor = new Instructor { HireDate = DateTime.Today };

            var result = _controller.Create(instructor, null);

            var viewResult = Assert.IsType<ViewResult>(result);
            Assert.NotNull(_controller.ViewBag.Courses);
        }

        #endregion

        #region Edit GET

        [Fact]
        public void Edit_GET_NullId_ReturnsBadRequest()
        {
            var result = _controller.Edit((int?)null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal((int)HttpStatusCode.BadRequest, statusResult.StatusCode);
        }

        [Fact]
        public void Edit_GET_ValidId_ReturnsViewWithInstructor()
        {
            var result = _controller.Edit(10);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<Instructor>(viewResult.Model);
            Assert.Equal("Abercrombie", model.LastName);
            Assert.NotNull(_controller.ViewBag.Courses);
        }

        [Fact]
        public void Edit_GET_PopulatesAssignedCoursesCorrectly()
        {
            _controller.Edit(10);

            var courses = _controller.ViewBag.Courses as List<AssignedCourseData>;
            Assert.NotNull(courses);
            // Instructor 10 is assigned to course 1050
            var assigned = courses.Where(c => c.Assigned).ToList();
            Assert.Single(assigned);
            Assert.Equal(1050, assigned.First().CourseID);
        }

        #endregion

        #region Delete GET

        [Fact]
        public void Delete_GET_NullId_ReturnsBadRequest()
        {
            var result = _controller.Delete(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal((int)HttpStatusCode.BadRequest, statusResult.StatusCode);
        }

        [Fact]
        public void Delete_GET_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Delete(999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Delete_GET_ValidId_ReturnsViewWithInstructor()
        {
            var result = _controller.Delete(10);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<Instructor>(viewResult.Model);
            Assert.Equal("Abercrombie", model.LastName);
        }

        #endregion

        #region Delete POST

        [Fact]
        public void DeleteConfirmed_RemovesInstructorAndRedirects()
        {
            var result = _controller.DeleteConfirmed(10);

            var redirectResult = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirectResult.ActionName);
            Assert.Single(_context.Instructors);
        }

        [Fact]
        public void DeleteConfirmed_ClearsDepartmentAdministrator()
        {
            // Department 1 has InstructorID = 10
            _controller.DeleteConfirmed(10);

            var dept = _context.Departments.Find(1);
            Assert.Null(dept.InstructorID);
        }

        [Fact]
        public void DeleteConfirmed_InstructorWithNoLinkedDepartment_Succeeds()
        {
            // Instructor 11 is linked to department 2. Delete inst 10 who is linked to dept 1.
            // After removing the department link check, we verify instructor is deleted.
            var result = _controller.DeleteConfirmed(10);
            Assert.IsType<RedirectToActionResult>(result);
        }

        #endregion
    }
}

